import { Notification } from './types';

// Simulate a database with mock data
const mockNotifications: Notification[] = [
  { id: 'n1', userId: 'user1', message: 'Welcome to the platform!', isRead: true, createdAt: new Date('2023-01-01T10:00:00Z') },
  { id: 'n2', userId: 'user1', message: 'Your subscription is expiring soon.', isRead: false, createdAt: new Date('2023-01-05T11:30:00Z') },
  { id: 'n3', userId: 'user2', message: 'New feature available!', isRead: false, createdAt: new Date('2023-01-02T09:00:00Z') },
  { id: 'n4', userId: 'user1', message: 'You have a new follower!', isRead: false, createdAt: new Date('2023-01-07T14:00:00Z') },
  { id: 'n5', userId: 'user1', message: 'Your post received 100 likes.', isRead: true, createdAt: new Date('2023-01-03T16:00:00Z') },
  { id: 'n6', userId: 'user1', message: 'Reminder: Meeting at 3 PM.', isRead: false, createdAt: new Date('2023-01-08T09:00:00Z') },
  { id: 'n7', userId: 'user2', message: 'Your order has shipped.', isRead: true, createdAt: new Date('2023-01-04T12:00:00Z') },
  { id: 'n8', userId: 'user1', message: 'Security alert: Unusual login attempt.', isRead: false, createdAt: new Date('2023-01-09T10:00:00Z') },
  { id: 'n9', userId: 'user1', message: 'Your profile was updated.', isRead: true, createdAt: new Date('2023-01-06T18:00:00Z') },
  { id: 'n10', userId: 'user1', message: 'New message from support.', isRead: false, createdAt: new Date('2023-01-10T11:00:00Z') },
  { id: 'n11', userId: 'user1', message: 'Your trial period ends tomorrow.', isRead: false, createdAt: new Date('2023-01-11T08:00:00Z') },
  { id: 'n12', userId: 'user1', message: 'Monthly report is ready.', isRead: true, createdAt: new Date('2023-01-12T13:00:00Z') },
];

/**
 * Retrieves a user's notifications, paginated and ordered unread-first.
 * @param userId The ID of the user.
 * @param page The current page number (1-indexed).
 * @param limit The number of notifications per page.
 * @returns An object containing the total count and the paginated list of notifications.
 */
export async function getNotificationsByUserId(
  userId: string,
  page: number,
  limit: number
): Promise<{ total: number; notifications: Notification[] }> {
  // Simulate async database call
  await new Promise(resolve => setTimeout(resolve, 50));

  const userNotifications = mockNotifications.filter(n => n.userId === userId);

  // Sort: unread (isRead: false) first, then by createdAt descending
  userNotifications.sort((a, b) => {
    // If one is unread and the other is read, unread comes first
    if (a.isRead !== b.isRead) {
      return a.isRead ? 1 : -1; // false (unread) comes before true (read)
    }
    // If both are read or both are unread, sort by createdAt descending
    return b.createdAt.getTime() - a.createdAt.getTime();
  });

  const total = userNotifications.length;
  const startIndex = (page - 1) * limit;
  const endIndex = startIndex + limit;

  const paginatedNotifications = userNotifications.slice(startIndex, endIndex);

  return {
    total,
    notifications: paginatedNotifications,
  };
}
