```aether:src/routes/notifications.ts
import { Hono } from 'hono';
import { getNotificationsByUserId } from '../db';

// Create a Hono router for notifications
const notificationsRouter = new Hono();

/**
 * GET /notifications
 * Lists the current user's notifications, paginated, with unread-first ordering.
 * Query Parameters:
 *   - page: The page number (default: 1)
 *   - limit: The number of items per page (default: 10)
 *
 * For this exercise, we'll assume a 'user1' as the current user.
 * In a real application, the userId would come from an authentication context.
 */
notificationsRouter.get('/', async (c) => {
  // In a real application, userId would be extracted from authentication context (e.g., JWT, session)
  // For this exercise, we'll use a hardcoded userId.
  const currentUserId = 'user1'; 

  const page = parseInt(c.req.query('page') || '1', 10);
  const limit = parseInt(c.req.query('limit') || '10', 10);

  if (isNaN(page) || page < 1) {
    return c.json({ error: 'Invalid page number. Must be a positive integer.' }, 400);
  }
  if (isNaN(limit) || limit < 1) {
    return c.json({ error: 'Invalid limit. Must be a positive integer.' }, 400);
  }

  try {
    const { total, notifications } = await getNotificationsByUserId(currentUserId, page, limit);

    return c.json({
      page,
      limit,
      total,
      totalPages: Math.ceil(total / limit),
      notifications,
    });
  } catch (error) {
    console.error('Failed to fetch notifications:', error);
    return c.json({ error: 'Internal server error' }, 500);
  }
});

export default notificationsRouter;
